sealed class LocationException: kotlin.Exception() {
    
    class Crypto(
        
        val v1: kotlin.String
        ) : LocationException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Network(
        
        val v1: kotlin.String
        ) : LocationException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Decode(
        
        val v1: kotlin.String
        ) : LocationException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class NotStarted(
        ) : LocationException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<LocationException> {
        override fun lift(error_buf: RustBuffer.ByValue): LocationException = FfiConverterTypeLocationError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeLocationError : FfiConverterRustBuffer<LocationException> {
    override fun read(buf: ByteBuffer): LocationException {
        

        return when(buf.getInt()) {
            1 -> LocationException.Crypto(
                FfiConverterString.read(buf),
                )
            2 -> LocationException.Network(
                FfiConverterString.read(buf),
                )
            3 -> LocationException.Decode(
                FfiConverterString.read(buf),
                )
            4 -> LocationException.NotStarted()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: LocationException): ULong {
        return when(value) {
            is LocationException.Crypto -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LocationException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LocationException.Decode -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LocationException.NotStarted -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: LocationException, buf: ByteBuffer) {
        when(value) {
            is LocationException.Crypto -> {
                buf.putInt(1)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LocationException.Network -> {
                buf.putInt(2)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LocationException.Decode -> {
                buf.putInt(3)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LocationException.NotStarted -> {
                buf.putInt(4)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * The kind of a polled pairing event.
 */

enum class PairEventKind {
    
    /**
     * A peer wants to pair (or our outbound Hello landed) — prompt the user.
     */
    PENDING_REQUEST,
    /**
     * The SAS visual gate is ready — fetch `pair_sas_challenge` and show it.
     */
    VERIFYING,
    /**
     * The peer sent their accept/reject.
     */
    PEER_RESPONDED,
    /**
     * Both sides accepted — call `pair_result`.
     */
    READY,
    /**
     * The session was rejected by either side.
     */
    REJECTED,
    /**
     * The session failed (SAS mismatch/cancel/timeout or a protocol error).
     */
    FAILED;

    


    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypePairEventKind: FfiConverterRustBuffer<PairEventKind> {
    override fun read(buf: ByteBuffer) = try {
        PairEventKind.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: PairEventKind) = 4UL

    override fun write(value: PairEventKind, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}





/**
 * Coarse pairing session phase (UI-facing).
 */

enum class PairState {
    
    HANDSHAKING,
    PENDING,
    /**
     * The SAS nonces are revealed + verified; both humans must clear the visual gate. No
     * `PairResult` is reachable from here.
     */
    VERIFYING,
    LOCAL_ACCEPTED,
    PEER_ACCEPTED,
    COMPLETE,
    REJECTED,
    FAILED;

    


    companion object
}


